import { Card, CardHeader, CardTitle, CardBody } from "reactstrap";
import React, { useState } from "react";
import { evaColumns } from "./columnSpec";
// ** Store
import { useSelector } from "react-redux";
import { evaUrl } from "../../urlConstants";
import TableComponent from "../common/TableComponent";

const IrsCompleted = () => {
  const UserDetails = useSelector((state) => (state && state.auth ? state.auth.userData : {}));
  const [screenType] = useState("EVAOY");
  const [filter] = useState({
    plantIds: UserDetails.plantids,
    formType: "F",
    SCREEN_TYPE: screenType,
    status: "12",
  });
  const actionColumn = () => {
    const actionsCol = {
      name: "Actions",
      selector: "status",
      minWidth: "250px",
      cell: (row) => {
        return <></>;
      },
    };
    return actionsCol;
  };

  const columns = [...evaColumns, actionColumn()];
  return (
    <div>
      <Card>
        <CardHeader>
          <CardTitle>{"Vehicle Details"}</CardTitle>
        </CardHeader>
        <CardBody>
          <TableComponent postData={filter} columns={columns} url={evaUrl} formType="F" />
        </CardBody>
      </Card>
    </div>
  );
};

export default IrsCompleted;
